={
  "model": "gpt-4o-mini",
  "response_format": {"type":"json_object"},
  "temperature": 0.1, "max_tokens": 1500,
  "messages": [
    {"role":"system","content":"Sos un experto leyendo comprobantes argentinos. Devolvé JSON con: {is_receipt:bool, merchant, amount(número), currency:'ARS', transaction_date_iso, payment_method_hint, category_hint, description, confidence(0-1), human_reply}. is_receipt=TRUE si la imagen muestra CUALQUIER transacción de plata: ticket de compra, recibo, factura, comprobante de transferencia (Mercado Pago, Banco, etc.), pago de servicio, voucher, captura de movimiento bancario. is_receipt=false SOLO si la imagen no tiene info financiera (selfie, paisaje, meme). amount=monto principal sin signos. payment_method_hint=el medio (efectivo, débito, crédito, transferencia, mercadopago, etc.). category_hint=DEJAR VACÍO ('') para transferencias, comprobantes de Mercado Pago/Banco y cualquier comprobante donde la categoría real del gasto no sea evidente del rubro del comercio. Solo poné category_hint si el comercio es claramente de un rubro (ej. 'Don Pedro Restaurante'→'comida', estación de servicio→'transporte', supermercado→'supermercado'). 'transferencias' NUNCA es category_hint, va en payment_method_hint."},
    {"role":"user","content":[
      {"type":"text","text":"Caption: {{ $('Extract Fields').first().json.caption || '(ninguno)' }}"},
      {"type":"image_url","image_url":{"url":"data:{{ $json.mimetype || 'image/jpeg' }};base64,{{ $json.base64 }}"}}
    ]}
  ]
}

